solution: ```class Solution {
    public int maxFreq(String s, int maxLetters, int minSize, int maxSize) {
        int n = s.length();
        int max = 0;
        Map<String, Integer> freq = new HashMap<>();
        for (int len = minSize; len <= Math.min(maxSize, n); len++) {
            int[] cnt = new int[26];
            int unique = 0;
            for (int i = 0; i < n; i++) {
                int idx = s.charAt(i) - 'a';
                if (cnt[idx]++ == 0) unique++;
                if (i >= len) {
                    int left = s.charAt(i - len) - 'a';
                    if (--cnt[left] == 0) unique--;
                }
                if (i >= len - 1 && unique <= maxLetters) {
                    String sub = s.substring(i - len + 1, i + 1);
                    freq.put(sub, freq.getOrDefault(sub, 0) + 1);
                    max = Math.max(max, freq.get(sub));
                }
            }
            if (max > 0) break;
        }
        return max;
    }
}
